import express from 'express';
import cors from 'cors';
import dotenv from 'dotenv';

dotenv.config();

const app = express();
const PORT = process.env.PORT || 3000;

// Middleware
app.use(cors());
app.use(express.json());

// Health check endpoint
app.get('/health', (req, res) => {
  res.json({ status: 'ok', timestamp: new Date().toISOString() });
});

// Basic routing structure
app.get('/', (req, res) => {
  res.json({
    message: 'PMP Intelligent Flashcard System API',
    version: '1.0.0',
    endpoints: {
      health: '/health',
      cards: '/api/cards',
      review: '/api/review',
      stats: '/api/stats',
      webhook: '/webhook/sync'
    }
  });
});

// Protected routes will be added here with authMiddleware
// app.use('/api', authMiddleware);
// app.use('/api/cards', cardsRouter);
// app.use('/api/review', reviewRouter);
// app.use('/api/stats', statsRouter);

// Webhook endpoint (no auth required)
app.post('/webhook/sync', async (req, res) => {
  // GitHub sync webhook - to be implemented
  res.json({ received: true });
});

// Error handler middleware
app.use(
  (err: any, req: express.Request, res: express.Response, next: express.NextFunction) => {
    console.error('Error:', err);
    res.status(err.status || 500).json({
      error: err.message || 'Internal Server Error'
    });
  }
);

// 404 handler
app.use((req, res) => {
  res.status(404).json({ error: 'Not Found' });
});

// Server startup
const start = async () => {
  try {
    app.listen(PORT, () => {
      console.log(`✓ Server running on port ${PORT}`);
      console.log(`✓ Environment: ${process.env.NODE_ENV || 'development'}`);
    });
  } catch (error) {
    console.error('✗ Failed to start server:', error);
    process.exit(1);
  }
};

// Graceful shutdown
process.on('SIGINT', async () => {
  console.log('Shutting down...');
  process.exit(0);
});

start();

export default app;

import React from 'react';
import { BrowserRouter as Router, Routes, Route } from 'react-router-dom';
import { HomePage } from './pages';
import { ReviewPage } from './pages/review';
import './App.css';

function App() {
  return (
    <Router>
      <Routes>
        <Route path="/" element={<HomePage />} />
        <Route path="/review" element={<ReviewPage />} />
      </Routes>
    </Router>
  );
}

export default App;

import React from 'react';
import ReactDOM from 'react-dom/client';
import { QueryClient, QueryClientProvider } from 'react-query';
import App from './App';
import './index.css';

const queryClient = new QueryClient();

const root = ReactDOM.createRoot(
  document.getElementById('root') as HTMLElement
);

root.render(
  <React.StrictMode>
    <QueryClientProvider client={queryClient}>
      <App />
    </QueryClientProvider>
  </React.StrictMode>
);

export interface Card {
  id: string;
  question: string;
  answer: string;
  chapter: string;
  domain: string;
  tags: string[];
  difficulty: 'easy' | 'medium' | 'hard';
  totalReviews: number;
  correctCount: number;
  nextReviewDate: string;
  interval: number;
  easeFactor: number;
  createdAt?: string;
  updatedAt?: string;
}

export interface ReviewSession {
  cardId: string;
  quality: number; // 0-3
  timeSpent: number; // seconds
}

export interface ReviewResponse {
  id: string;
  cardId: string;
  quality: number;
  timeSpent: number;
  createdAt: string;
  cardUpdated: boolean;
  nextReviewDate: string;
}

export interface Stats {
  totalCards: number;
  masteredCards: number;
  learningCards: number;
  newCards: number;
  overdueCards: number;
  totalReviews: number;
  correctReviews: number;
  masteryPercentage: number;
  byDomain?: Record<string, any>;
  byChapter?: Record<string, any>;
}

export interface User {
  id: string;
  email: string;
  username: string;
  createdAt: string;
}

export interface ApiError {
  error: string;
  message?: string;
  status?: number;
}

import React, { useState } from 'react';
import { Card as CardType } from '../types';

interface CardProps {
  card: CardType;
  onRate: (quality: number) => void;
  isLoading?: boolean;
}

export const Card: React.FC<CardProps> = ({ card, onRate, isLoading = false }) => {
  const [isFlipped, setIsFlipped] = useState(false);

  return (
    <div className="w-full max-w-2xl mx-auto p-6">
      {/* Card */}
      <div
        className="bg-white rounded-lg shadow-lg p-8 min-h-64 cursor-pointer transform transition-transform duration-500"
        onClick={() => setIsFlipped(!isFlipped)}
        style={{
          transform: isFlipped ? 'scaleX(-1)' : 'scaleX(1)'
        }}
      >
        <div className="text-center">
          {!isFlipped ? (
            <>
              <p className="text-sm text-gray-500 mb-4">Question</p>
              <p className="text-xl font-semibold text-gray-900">{card.question}</p>
            </>
          ) : (
            <>
              <p className="text-sm text-gray-500 mb-4">Answer</p>
              <p className="text-lg text-gray-900 whitespace-pre-wrap">{card.answer}</p>
            </>
          )}
        </div>
      </div>

      {/* Rating buttons */}
      <div className="mt-8 grid grid-cols-4 gap-4">
        <button
          onClick={() => onRate(0)}
          disabled={isLoading}
          className="px-4 py-2 bg-red-500 text-white rounded hover:bg-red-600 disabled:opacity-50 disabled:cursor-not-allowed transition-colors"
        >
          Incorrect (0)
        </button>
        <button
          onClick={() => onRate(1)}
          disabled={isLoading}
          className="px-4 py-2 bg-yellow-500 text-white rounded hover:bg-yellow-600 disabled:opacity-50 disabled:cursor-not-allowed transition-colors"
        >
          Difficult (1)
        </button>
        <button
          onClick={() => onRate(2)}
          disabled={isLoading}
          className="px-4 py-2 bg-blue-500 text-white rounded hover:bg-blue-600 disabled:opacity-50 disabled:cursor-not-allowed transition-colors"
        >
          Good (2)
        </button>
        <button
          onClick={() => onRate(3)}
          disabled={isLoading}
          className="px-4 py-2 bg-green-500 text-white rounded hover:bg-green-600 disabled:opacity-50 disabled:cursor-not-allowed transition-colors"
        >
          Easy (3)
        </button>
      </div>

      {/* Card metadata */}
      <div className="mt-6 text-xs text-gray-500 text-center space-y-1">
        <div>
          <span className="font-semibold">{card.chapter}</span> ·
          <span className="font-semibold ml-1">{card.domain}</span>
        </div>
        <div>
          Difficulty: <span className="font-semibold">{card.difficulty}</span> ·
          Reviews: <span className="font-semibold">{card.totalReviews}</span>
        </div>
        {card.lastReviewDate && (
          <div>
            Next review: <span className="font-semibold">{new Date(card.nextReviewDate).toLocaleDateString()}</span>
          </div>
        )}
      </div>
    </div>
  );
};

import React, { useEffect, useState } from 'react';
import { useNavigate } from 'react-router-dom';
import { Stats } from '../types';

export const HomePage: React.FC = () => {
  const navigate = useNavigate();
  const [stats, setStats] = useState<Stats | null>(null);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    // TODO: Load statistics from API
    setLoading(false);
    setStats({
      totalCards: 856,
      masteredCards: 312,
      learningCards: 284,
      newCards: 260,
      overdueCards: 45,
      totalReviews: 1245,
      correctReviews: 987,
      masteryPercentage: 36
    });
  }, []);

  if (loading) {
    return (
      <div className="min-h-screen bg-gray-50 flex items-center justify-center">
        <p>Loading...</p>
      </div>
    );
  }

  return (
    <div className="min-h-screen bg-gray-50 p-8">
      <div className="max-w-6xl mx-auto">
        {/* Header */}
        <div className="mb-12">
          <h1 className="text-4xl font-bold mb-2 text-gray-900">PMP Flashcard System</h1>
          <p className="text-lg text-gray-600">
            Intelligent spaced-repetition learning for PMP certification
          </p>
        </div>

        {/* Statistics Grid */}
        {stats && (
          <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-6 mb-12">
            {/* Total Cards */}
            <div className="bg-white rounded-lg p-6 shadow hover:shadow-lg transition-shadow">
              <p className="text-gray-600 text-sm font-semibold mb-2 uppercase">Total Cards</p>
              <p className="text-3xl font-bold text-blue-600">{stats.totalCards}</p>
            </div>

            {/* Mastery Percentage */}
            <div className="bg-white rounded-lg p-6 shadow hover:shadow-lg transition-shadow">
              <p className="text-gray-600 text-sm font-semibold mb-2 uppercase">Mastery</p>
              <p className="text-3xl font-bold text-green-600">{stats.masteryPercentage}%</p>
            </div>

            {/* Overdue Cards */}
            <div className="bg-white rounded-lg p-6 shadow hover:shadow-lg transition-shadow">
              <p className="text-gray-600 text-sm font-semibold mb-2 uppercase">Overdue</p>
              <p className="text-3xl font-bold text-red-600">{stats.overdueCards}</p>
            </div>

            {/* Total Reviews */}
            <div className="bg-white rounded-lg p-6 shadow hover:shadow-lg transition-shadow">
              <p className="text-gray-600 text-sm font-semibold mb-2 uppercase">Reviews</p>
              <p className="text-3xl font-bold text-purple-600">{stats.totalReviews}</p>
            </div>
          </div>
        )}

        {/* Card Status Breakdown */}
        {stats && (
          <div className="bg-white rounded-lg p-8 shadow mb-12">
            <h2 className="text-2xl font-bold mb-6 text-gray-900">Card Status</h2>
            <div className="grid grid-cols-2 md:grid-cols-4 gap-6">
              <div>
                <p className="text-gray-600 text-sm font-semibold mb-2">New</p>
                <p className="text-2xl font-bold text-blue-600">{stats.newCards}</p>
              </div>
              <div>
                <p className="text-gray-600 text-sm font-semibold mb-2">Learning</p>
                <p className="text-2xl font-bold text-yellow-600">{stats.learningCards}</p>
              </div>
              <div>
                <p className="text-gray-600 text-sm font-semibold mb-2">Mastered</p>
                <p className="text-2xl font-bold text-green-600">{stats.masteredCards}</p>
              </div>
              <div>
                <p className="text-gray-600 text-sm font-semibold mb-2">Success Rate</p>
                <p className="text-2xl font-bold text-purple-600">
                  {stats.totalReviews > 0
                    ? Math.round((stats.correctReviews / stats.totalReviews) * 100)
                    : 0}%
                </p>
              </div>
            </div>
          </div>
        )}

        {/* Action Buttons */}
        <div className="flex flex-col sm:flex-row gap-4 justify-center">
          <button
            onClick={() => navigate('/review')}
            className="px-8 py-4 bg-blue-600 text-white rounded-lg font-semibold hover:bg-blue-700 transition-colors text-lg"
          >
            Start Review Session
          </button>
          <button
            className="px-8 py-4 bg-gray-200 text-gray-900 rounded-lg font-semibold hover:bg-gray-300 transition-colors text-lg"
            disabled
          >
            View Statistics (Coming Soon)
          </button>
        </div>

        {/* Info Section */}
        <div className="mt-12 bg-blue-50 rounded-lg p-6 border border-blue-200">
          <p className="text-sm text-gray-700">
            <strong>✓ System Status:</strong> Backend initialized and ready. Frontend connected.
            Use the "Start Review Session" button to begin your learning journey.
          </p>
        </div>
      </div>
    </div>
  );
};

import React, { useEffect, useState } from 'react';
import { Card as CardType } from '../types';
import { Card } from '../components/Card';

export const ReviewPage: React.FC = () => {
  const [cards, setCards] = useState<CardType[]>([]);
  const [currentIndex, setCurrentIndex] = useState(0);
  const [loading, setLoading] = useState(true);
  const [reviewCompleted, setReviewCompleted] = useState(false);
  const [reviewCount, setReviewCount] = useState(0);

  useEffect(() => {
    // TODO: Load today's cards from API
    setLoading(false);
    // Mock data for now
    setCards([
      {
        id: '1',
        question: 'What is the primary purpose of the PMP certification?',
        answer:
          'The PMP (Project Management Professional) certification validates the knowledge and skills required to lead and manage projects effectively across various industries.',
        chapter: 'CH.1',
        domain: 'Domain I',
        tags: ['certification', 'foundation'],
        difficulty: 'easy',
        totalReviews: 5,
        correctCount: 4,
        nextReviewDate: '2026-05-10',
        interval: 2.5,
        easeFactor: 2.5,
        createdAt: '2026-05-01',
        updatedAt: '2026-05-04'
      },
      {
        id: '2',
        question: 'Define project scope in project management.',
        answer:
          'Project scope is the work that must be performed to deliver a product, service, or result with the specified features and functions. It defines what is included and excluded from the project.',
        chapter: 'CH.2',
        domain: 'Domain II',
        tags: ['scope', 'planning'],
        difficulty: 'medium',
        totalReviews: 3,
        correctCount: 2,
        nextReviewDate: '2026-05-06',
        interval: 1.8,
        easeFactor: 2.3,
        createdAt: '2026-05-02',
        updatedAt: '2026-05-04'
      },
      {
        id: '3',
        question: 'What are the five process groups in project management?',
        answer:
          'The five process groups are: Initiating, Planning, Executing, Monitoring and Controlling, and Closing. They represent the phases of the project lifecycle.',
        chapter: 'CH.1',
        domain: 'Domain I',
        tags: ['processes', 'framework'],
        difficulty: 'medium',
        totalReviews: 2,
        correctCount: 1,
        nextReviewDate: '2026-05-07',
        interval: 1.3,
        easeFactor: 2.2,
        createdAt: '2026-05-01',
        updatedAt: '2026-05-04'
      }
    ]);
  }, []);

  const handleRate = async (quality: number) => {
    // TODO: Submit review result to API
    console.log(`Rated card ${cards[currentIndex].id} with quality ${quality}`);
    setReviewCount(reviewCount + 1);

    if (currentIndex < cards.length - 1) {
      setCurrentIndex(currentIndex + 1);
    } else {
      setReviewCompleted(true);
    }
  };

  const handleReset = () => {
    setCurrentIndex(0);
    setReviewCompleted(false);
    setReviewCount(0);
  };

  if (loading) {
    return (
      <div className="min-h-screen bg-gray-50 flex items-center justify-center">
        <p className="text-lg text-gray-600">Loading cards...</p>
      </div>
    );
  }

  if (cards.length === 0) {
    return (
      <div className="min-h-screen bg-gray-50 flex items-center justify-center p-8">
        <div className="text-center">
          <p className="text-2xl font-bold text-gray-900 mb-4">No Cards Available</p>
          <p className="text-gray-600 mb-8">There are no cards to review at the moment.</p>
          <a
            href="/"
            className="px-6 py-2 bg-blue-600 text-white rounded-lg font-semibold hover:bg-blue-700"
          >
            Return to Home
          </a>
        </div>
      </div>
    );
  }

  if (reviewCompleted) {
    return (
      <div className="min-h-screen bg-gray-50 flex items-center justify-center p-8">
        <div className="bg-white rounded-lg shadow-lg p-12 max-w-md text-center">
          <div className="text-6xl mb-6">🎉</div>
          <h1 className="text-3xl font-bold text-gray-900 mb-4">Review Complete!</h1>
          <p className="text-lg text-gray-600 mb-8">
            You reviewed <span className="font-bold text-blue-600">{reviewCount}</span> card
            {reviewCount !== 1 ? 's' : ''} today.
          </p>
          <div className="space-y-3">
            <button
              onClick={handleReset}
              className="w-full px-6 py-3 bg-blue-600 text-white rounded-lg font-semibold hover:bg-blue-700 transition-colors"
            >
              Review Again
            </button>
            <a
              href="/"
              className="block px-6 py-3 bg-gray-200 text-gray-900 rounded-lg font-semibold hover:bg-gray-300 transition-colors"
            >
              Return to Home
            </a>
          </div>
        </div>
      </div>
    );
  }

  const currentCard = cards[currentIndex];
  const progress = ((currentIndex + 1) / cards.length) * 100;

  return (
    <div className="min-h-screen bg-gray-50 p-8">
      <div className="max-w-4xl mx-auto">
        {/* Header */}
        <div className="mb-8">
          <a
            href="/"
            className="text-blue-600 hover:text-blue-700 font-semibold mb-4 inline-block"
          >
            ← Back to Home
          </a>
          <h1 className="text-3xl font-bold text-gray-900">Review Session</h1>
        </div>

        {/* Progress Bar */}
        <div className="mb-8">
          <div className="flex justify-between items-center mb-2">
            <p className="text-sm font-semibold text-gray-700">
              Progress: {currentIndex + 1} / {cards.length}
            </p>
            <p className="text-sm font-semibold text-gray-700">{Math.round(progress)}%</p>
          </div>
          <div className="w-full bg-gray-200 rounded-full h-3">
            <div
              className="bg-blue-600 h-3 rounded-full transition-all duration-300"
              style={{ width: `${progress}%` }}
            ></div>
          </div>
        </div>

        {/* Card Component */}
        <Card
          card={currentCard}
          onRate={handleRate}
          isLoading={false}
        />

        {/* Footer Info */}
        <div className="mt-8 text-center text-sm text-gray-600">
          <p>Reviewed today: {reviewCount}</p>
        </div>
      </div>
    </div>
  );
};

