/**
 * Markdown Parser Service
 * Extracts flashcards from Markdown notes with frontmatter
 */

/**
 * Represents a parsed card extracted from markdown
 */
export interface ParsedCard {
  /** The question/prompt text */
  question: string;
  /** The answer/content text */
  answer: string;
  /** Card type: 'summary' for bullet points, 'exam' for exam questions */
  type: 'summary' | 'exam';
  /** Source file name (from filename parameter) */
  sourceFile: string;
  /** Chapter/topic from frontmatter (e.g., "基礎概念") */
  chapter: string;
  /** Domain classification (e.g., "Domain I") */
  domain?: string;
  /** Optional difficulty level */
  difficulty?: string;
}

/**
 * Extracts frontmatter from markdown content
 * Frontmatter is YAML between --- delimiters at the start of the file
 */
function extractFrontmatter(markdown: string): Record<string, any> {
  const frontmatterRegex = /^---\n([\s\S]*?)\n---/;
  const match = markdown.match(frontmatterRegex);

  if (!match || !match[1]) {
    return {};
  }

  const frontmatterContent = match[1];
  const result: Record<string, any> = {};

  // Simple YAML parser for basic key: value pairs
  const lines = frontmatterContent.split('\n');
  for (const line of lines) {
    if (!line.trim() || line.startsWith('#')) continue;

    const colonIndex = line.indexOf(':');
    if (colonIndex === -1) continue;

    const key = line.substring(0, colonIndex).trim();
    const value = line.substring(colonIndex + 1).trim();

    // Remove quotes if present
    let cleanValue = value;
    if ((cleanValue.startsWith('"') && cleanValue.endsWith('"')) ||
        (cleanValue.startsWith("'") && cleanValue.endsWith("'"))) {
      cleanValue = cleanValue.slice(1, -1);
    }

    result[key] = cleanValue;
  }

  return result;
}

/**
 * Extracts the main title from markdown
 * Uses the first H1 heading (# Title)
 */
function extractTitle(markdown: string): string {
  const titleRegex = /^# (.+)$/m;
  const match = markdown.match(titleRegex);
  return match ? match[1].trim() : 'Untitled';
}

/**
 * Extracts bullet points from a specific section
 * Looks for section headers like "### 🎯 重點摘要"
 */
function extractSectionBullets(markdown: string, sectionPattern: RegExp): string[] {
  // Find the section start
  const sectionMatch = markdown.match(sectionPattern);
  if (!sectionMatch) {
    return [];
  }

  const sectionStart = sectionMatch.index || 0;
  const sectionHeader = sectionMatch[0];
  const startIndex = sectionStart + sectionHeader.length;

  // Find the end of the section (next heading or end of file)
  const remainingContent = markdown.substring(startIndex);
  const nextHeadingRegex = /\n(#+\s)/; // Matches next heading
  const nextHeadingMatch = remainingContent.match(nextHeadingRegex);

  let sectionContent: string;
  if (nextHeadingMatch) {
    sectionContent = remainingContent.substring(0, nextHeadingMatch.index);
  } else {
    sectionContent = remainingContent;
  }

  // Extract bullet points (lines starting with "- ")
  const bulletRegex = /^- (.+)$/gm;
  const bullets: string[] = [];
  let match;

  while ((match = bulletRegex.exec(sectionContent)) !== null) {
    const bullet = match[1].trim();
    if (bullet) {
      bullets.push(bullet);
    }
  }

  return bullets;
}

/**
 * Extracts exam questions from the "考試要點" section
 * Looks for patterns like "- ✅ 定義題：「XXX」"
 */
function extractExamQuestions(markdown: string): string[] {
  const examPattern = /### 📋\s*考試要點/i;
  const bullets = extractSectionBullets(markdown, examPattern);

  // Filter and clean exam questions
  const questions: string[] = [];

  for (const bullet of bullets) {
    // Remove emoji prefixes and type markers
    // Format: "✅ 定義題：「XXX」" -> "定義題：XXX"
    const cleaned = bullet
      .replace(/^✅\s*/i, '') // Remove checkmark emoji
      .replace(/^❌\s*/i, '') // Remove cross emoji
      .replace(/「(.+?)」/g, '$1') // Convert 「」 to plain text
      .trim();

    if (cleaned) {
      questions.push(cleaned);
    }
  }

  return questions;
}

/**
 * Parses markdown content and extracts flashcards
 *
 * @param markdown - The markdown content to parse
 * @param fileName - The source filename (used in sourceFile field)
 * @returns Array of parsed cards
 *
 * @example
 * const cards = parseMarkdown(markdownContent, 'ch1-basics.md');
 * // Returns cards with type 'summary' and 'exam'
 */
export function parseMarkdown(markdown: string, fileName: string): ParsedCard[] {
  const cards: ParsedCard[] = [];

  // Extract frontmatter
  const frontmatter = extractFrontmatter(markdown);
  const chapter = frontmatter.chapter || 'Unknown';
  const domain = frontmatter.domain || undefined;
  const difficulty = frontmatter.difficulty || undefined;

  // Extract title to use as base question
  const title = extractTitle(markdown);

  // Extract summary bullet points
  const summaryPattern = /### 🎯\s*重點摘要/i;
  const summaryBullets = extractSectionBullets(markdown, summaryPattern);

  for (const bullet of summaryBullets) {
    cards.push({
      question: `[${title}] ${bullet}`,
      answer: bullet,
      type: 'summary',
      sourceFile: fileName,
      chapter,
      domain,
      difficulty: difficulty || 'medium'
    });
  }

  // Extract exam questions
  const examQuestions = extractExamQuestions(markdown);

  for (const question of examQuestions) {
    cards.push({
      question: `[${title}] ${question}`,
      answer: question,
      type: 'exam',
      sourceFile: fileName,
      chapter,
      domain,
      difficulty: difficulty || 'hard'
    });
  }

  return cards;
}

export default {
  parseMarkdown,
  extractFrontmatter,
  extractTitle,
  extractSectionBullets,
  extractExamQuestions
};

/**
 * Card Generator Service
 * Generates and manages flashcards from markdown files
 */

import { PrismaClient } from '@prisma/client';
import { parseMarkdown, ParsedCard } from './markdownParser';

const prisma = new PrismaClient();

/**
 * Result of card generation from a markdown file
 */
export interface CardGenerationResult {
  /** Number of new cards created */
  created: number;
  /** Number of existing cards updated */
  updated: number;
  /** Total cards processed */
  total: number;
}

/**
 * Generates cards from markdown content for a user
 *
 * @param userId - The user ID who owns these cards
 * @param markdownContent - The markdown content to parse
 * @param fileName - The source filename
 * @returns Result with counts of created/updated cards
 *
 * @example
 * const result = await generateCardsFromMarkdown(
 *   'user123',
 *   markdownContent,
 *   'ch1-basics.md'
 * );
 * console.log(`Created ${result.created}, Updated ${result.updated}`);
 */
export async function generateCardsFromMarkdown(
  userId: string,
  markdownContent: string,
  fileName: string
): Promise<CardGenerationResult> {
  // Parse the markdown to extract cards
  const parsedCards = parseMarkdown(markdownContent, fileName);

  let created = 0;
  let updated = 0;

  // Process each parsed card
  for (const parsed of parsedCards) {
    try {
      // Check if a card with the same sourceFile and question already exists
      const existingCard = await prisma.card.findFirst({
        where: {
          userId,
          sourceFile: parsed.sourceFile,
          question: parsed.question
        }
      });

      if (existingCard) {
        // Update existing card
        await prisma.card.update({
          where: { id: existingCard.id },
          data: {
            answer: parsed.answer,
            type: parsed.type,
            chapter: parsed.chapter,
            domain: parsed.domain || existingCard.domain,
            difficulty: parsed.difficulty || 'medium',
            updatedAt: new Date()
          }
        });
        updated++;
      } else {
        // Create new card
        await prisma.card.create({
          data: {
            userId,
            sourceFile: parsed.sourceFile,
            question: parsed.question,
            answer: parsed.answer,
            type: parsed.type,
            chapter: parsed.chapter,
            domain: parsed.domain || 'Unknown',
            difficulty: parsed.difficulty || 'medium',
            tags: [parsed.chapter]
          }
        });
        created++;
      }
    } catch (error) {
      console.error(`Error processing card "${parsed.question}":`, error);
      // Continue processing other cards even if one fails
      throw error;
    }
  }

  return {
    created,
    updated,
    total: parsedCards.length
  };
}

/**
 * Deletes all cards associated with a specific markdown file
 *
 * @param userId - The user ID who owns the cards
 * @param sourceFile - The source filename to delete cards for
 * @returns Number of cards deleted
 *
 * @example
 * const deleted = await deleteCardsForFile('user123', 'ch1-basics.md');
 * console.log(`Deleted ${deleted} cards`);
 */
export async function deleteCardsForFile(
  userId: string,
  sourceFile: string
): Promise<number> {
  const result = await prisma.card.deleteMany({
    where: {
      userId,
      sourceFile
    }
  });

  return result.count;
}

/**
 * Gets all cards for a user organized by source file
 *
 * @param userId - The user ID
 * @returns Object mapping filename to cards
 */
export async function getCardsByFile(userId: string): Promise<Record<string, any[]>> {
  const cards = await prisma.card.findMany({
    where: { userId },
    orderBy: { sourceFile: 'asc' }
  });

  const cardsByFile: Record<string, any[]> = {};

  for (const card of cards) {
    if (!cardsByFile[card.sourceFile]) {
      cardsByFile[card.sourceFile] = [];
    }
    cardsByFile[card.sourceFile].push(card);
  }

  return cardsByFile;
}

/**
 * Gets cards by type (summary or exam)
 *
 * @param userId - The user ID
 * @param type - The card type ('summary' or 'exam')
 * @returns Array of cards of the specified type
 */
export async function getCardsByType(
  userId: string,
  type: 'summary' | 'exam'
): Promise<any[]> {
  return prisma.card.findMany({
    where: {
      userId,
      type
    },
    orderBy: { createdAt: 'desc' }
  });
}

/**
 * Gets statistics about cards
 *
 * @param userId - The user ID
 * @returns Card statistics
 */
export async function getCardStats(userId: string): Promise<{
  total: number;
  byType: Record<string, number>;
  byChapter: Record<string, number>;
  byDifficulty: Record<string, number>;
}> {
  const cards = await prisma.card.findMany({
    where: { userId }
  });

  const stats = {
    total: cards.length,
    byType: { summary: 0, exam: 0 },
    byChapter: {} as Record<string, number>,
    byDifficulty: { easy: 0, medium: 0, hard: 0 }
  };

  for (const card of cards) {
    // Count by type
    if (card.type === 'summary' || card.type === 'exam') {
      stats.byType[card.type]++;
    }

    // Count by chapter
    if (!stats.byChapter[card.chapter]) {
      stats.byChapter[card.chapter] = 0;
    }
    stats.byChapter[card.chapter]++;

    // Count by difficulty
    if (card.difficulty in stats.byDifficulty) {
      stats.byDifficulty[card.difficulty as keyof typeof stats.byDifficulty]++;
    }
  }

  return stats;
}

