/**
 * Review Engine - SM-2 Spaced Repetition Algorithm Implementation
 */

export interface ReviewResult {
  quality: number; // 0-3
  timeSpent: number; // seconds
}

/**
 * Calculate next interval and ease factor based on SM-2 algorithm
 *
 * @param previousInterval - Current interval in days
 * @param previousFactor - Current ease factor
 * @param quality - User's quality response (0-3)
 *   0 = wrong (incorrect)
 *   1 = hard (barely correct)
 *   2 = ok (correct)
 *   3 = easy (very easy)
 * @returns New interval and ease factor
 */
export function calculateNextInterval(
  previousInterval: number,
  previousFactor: number,
  quality: number
): { interval: number; factor: number } {
  let newFactor = previousFactor;
  let newInterval = previousInterval;

  if (quality >= 3) {
    // 答對簡單：增加間隔和 factor
    newInterval = previousInterval * 2.5;
    newFactor = Math.max(1.3, previousFactor + 0.1);
  } else if (quality === 2) {
    // 答對 OK：中等增加
    newInterval = previousInterval * 1.3;
    newFactor = previousFactor;
  } else if (quality === 1) {
    // 勉強答對：輕微增加
    newInterval = previousInterval * 1.1;
    newFactor = Math.max(1.3, previousFactor - 0.1);
  } else {
    // 答錯：重置
    newInterval = 1;
    newFactor = 2.5;
  }

  return { interval: newInterval, factor: newFactor };
}

/**
 * Calculate next review date based on interval
 *
 * @param interval - Interval in days
 * @returns Next review date at midnight UTC
 */
export function getNextReviewDate(interval: number): Date {
  const date = new Date();
  date.setDate(date.getDate() + Math.ceil(interval));
  date.setHours(0, 0, 0, 0);
  return date;
}

/**
 * Determine if a card is overdue for review
 */
export function isCardOverdue(nextReviewDate: Date): boolean {
  const today = new Date();
  today.setHours(0, 0, 0, 0);
  return nextReviewDate <= today;
}

/**
 * Calculate days until next review
 */
export function daysUntilReview(nextReviewDate: Date): number {
  const today = new Date();
  today.setHours(0, 0, 0, 0);
  const nextDate = new Date(nextReviewDate);
  nextDate.setHours(0, 0, 0, 0);

  const diffTime = nextDate.getTime() - today.getTime();
  const diffDays = diffTime / (1000 * 60 * 60 * 24);

  return Math.ceil(diffDays);
}

/**
 * Get quality score from user input
 * Maps user rating to quality value
 */
export function getQualityFromRating(
  rating: 'wrong' | 'hard' | 'ok' | 'easy'
): number {
  const qualityMap: Record<string, number> = {
    'wrong': 0,
    'hard': 1,
    'ok': 2,
    'easy': 3
  };

  return qualityMap[rating] ?? 0;
}

import {
  calculateNextInterval,
  getNextReviewDate,
  isCardOverdue,
  daysUntilReview,
  getQualityFromRating
} from '../../src/services/reviewEngine';

describe('ReviewEngine', () => {
  describe('calculateNextInterval', () => {
    it('答對簡單應該大幅增加間隔', () => {
      const result = calculateNextInterval(1, 2.5, 3);
      expect(result.interval).toBe(2.5); // 1 * 2.5
      expect(result.factor).toBeGreaterThan(2.5);
      expect(result.factor).toBeCloseTo(2.6); // 2.5 + 0.1
    });

    it('答對 OK 應該輕微增加間隔', () => {
      const result = calculateNextInterval(2.5, 2.5, 2);
      expect(result.interval).toBeCloseTo(3.25); // 2.5 * 1.3
      expect(result.factor).toBe(2.5); // factor 不變
    });

    it('答對難（勉強）應該輕微增加', () => {
      const result = calculateNextInterval(5, 2.8, 1);
      expect(result.interval).toBeCloseTo(5.5); // 5 * 1.1
      expect(result.factor).toBe(2.7); // 2.8 - 0.1
    });

    it('答錯應該重置', () => {
      const result = calculateNextInterval(10, 3.0, 0);
      expect(result.interval).toBe(1);
      expect(result.factor).toBe(2.5);
    });

    it('factor 應該不低於 1.3', () => {
      const result = calculateNextInterval(1, 1.3, 1);
      expect(result.factor).toBe(1.3); // Math.max(1.3, 1.3 - 0.1)
    });

    it('應該正確處理多次複習', () => {
      let interval = 1;
      let factor = 2.5;

      // Day 1: 新卡片
      expect(interval).toBe(1);

      // Day 2: 答對簡單
      let result = calculateNextInterval(interval, factor, 3);
      interval = result.interval;
      factor = result.factor;
      expect(interval).toBe(2.5);

      // Day 4: 答對 OK
      result = calculateNextInterval(interval, factor, 2);
      interval = result.interval;
      factor = result.factor;
      expect(interval).toBeCloseTo(3.25);

      // Day 7: 答錯
      result = calculateNextInterval(interval, factor, 0);
      interval = result.interval;
      factor = result.factor;
      expect(interval).toBe(1);
      expect(factor).toBe(2.5);
    });
  });

  describe('getNextReviewDate', () => {
    it('應該正確計算下次複習日期', () => {
      const date = getNextReviewDate(5);
      const expected = new Date();
      expected.setDate(expected.getDate() + 5);
      expected.setHours(0, 0, 0, 0);

      expect(date.getTime()).toBe(expected.getTime());
    });

    it('應該向上取整天數', () => {
      const date = getNextReviewDate(2.3);
      const expected = new Date();
      expected.setDate(expected.getDate() + 3); // ceil(2.3) = 3
      expected.setHours(0, 0, 0, 0);

      expect(date.getTime()).toBe(expected.getTime());
    });

    it('應該總是返回午夜時間', () => {
      const date = getNextReviewDate(1);
      expect(date.getHours()).toBe(0);
      expect(date.getMinutes()).toBe(0);
      expect(date.getSeconds()).toBe(0);
      expect(date.getMilliseconds()).toBe(0);
    });

    it('應該處理 0 間隔', () => {
      const date = getNextReviewDate(0);
      const today = new Date();
      today.setHours(0, 0, 0, 0);

      expect(date.getTime()).toBe(today.getTime());
    });
  });

  describe('isCardOverdue', () => {
    it('應該檢測逾期卡片', () => {
      const yesterday = new Date();
      yesterday.setDate(yesterday.getDate() - 1);

      expect(isCardOverdue(yesterday)).toBe(true);
    });

    it('應該檢測正常卡片', () => {
      const tomorrow = new Date();
      tomorrow.setDate(tomorrow.getDate() + 1);

      expect(isCardOverdue(tomorrow)).toBe(false);
    });

    it('應該將今天視為逾期', () => {
      const today = new Date();
      today.setHours(0, 0, 0, 0);

      expect(isCardOverdue(today)).toBe(true);
    });
  });

  describe('daysUntilReview', () => {
    it('應該計算天數直到複習', () => {
      const future = new Date();
      future.setDate(future.getDate() + 5);

      const days = daysUntilReview(future);
      expect(days).toBe(5);
    });

    it('應該返回負數表示逾期', () => {
      const past = new Date();
      past.setDate(past.getDate() - 3);

      const days = daysUntilReview(past);
      expect(days).toBeLessThan(0);
    });

    it('應該返回 0 表示今天', () => {
      const today = new Date();
      today.setHours(0, 0, 0, 0);

      const days = daysUntilReview(today);
      expect(days).toBe(0);
    });
  });

  describe('getQualityFromRating', () => {
    it('應該映射 wrong 到 0', () => {
      expect(getQualityFromRating('wrong')).toBe(0);
    });

    it('應該映射 hard 到 1', () => {
      expect(getQualityFromRating('hard')).toBe(1);
    });

    it('應該映射 ok 到 2', () => {
      expect(getQualityFromRating('ok')).toBe(2);
    });

    it('應該映射 easy 到 3', () => {
      expect(getQualityFromRating('easy')).toBe(3);
    });

    it('應該返回 0 作為無效值的默認值', () => {
      expect(getQualityFromRating('invalid' as any)).toBe(0);
    });
  });
});

import { Router } from 'express';
import { AuthRequest, authMiddleware } from '../middleware/auth';
import { prisma } from '../config/database';
import { calculateNextInterval, getNextReviewDate } from '../services/reviewEngine';

const router = Router();

// 提交複習結果
router.post('/submit', authMiddleware, async (req: AuthRequest, res) => {
  try {
    const { cardId, quality, timeSpent } = req.body;

    // 驗證 quality 值
    if (quality < 0 || quality > 3) {
      return res.status(400).json({ error: 'Invalid quality value (must be 0-3)' });
    }

    if (!cardId) {
      return res.status(400).json({ error: 'Missing cardId' });
    }

    // 記錄複習
    const review = await prisma.reviewRecord.create({
      data: {
        userId: req.userId!,
        cardId,
        quality,
        timeSpent: timeSpent || 0
      }
    });

    // 查詢卡片
    const card = await prisma.card.findUnique({
      where: { id: cardId }
    });

    if (!card) {
      return res.status(404).json({ error: 'Card not found' });
    }

    // 驗證卡片屬於該用戶
    if (card.userId !== req.userId) {
      return res.status(403).json({ error: 'Unauthorized' });
    }

    // 計算新的間隔和 factor
    const { interval, factor } = calculateNextInterval(
      card.interval,
      card.easeFactor,
      quality
    );

    const nextReviewDate = getNextReviewDate(interval);

    // 更新卡片
    const updatedCard = await prisma.card.update({
      where: { id: cardId },
      data: {
        totalReviews: card.totalReviews + 1,
        correctCount: quality > 0 ? card.correctCount + 1 : card.correctCount,
        lastReviewDate: new Date(),
        nextReviewDate,
        interval,
        easeFactor: factor
      }
    });

    res.json({
      review,
      card: updatedCard
    });
  } catch (error) {
    console.error('Review submission error:', error);
    res.status(500).json({ error: 'Failed to submit review' });
  }
});

// 取得複習歷史
router.get('/history/:cardId', authMiddleware, async (req: AuthRequest, res) => {
  try {
    const { cardId } = req.params;

    // 驗證卡片屬於該用戶
    const card = await prisma.card.findUnique({
      where: { id: cardId }
    });

    if (!card) {
      return res.status(404).json({ error: 'Card not found' });
    }

    if (card.userId !== req.userId) {
      return res.status(403).json({ error: 'Unauthorized' });
    }

    // 取得複習歷史
    const reviews = await prisma.reviewRecord.findMany({
      where: {
        userId: req.userId,
        cardId
      },
      orderBy: { createdAt: 'desc' },
      take: 50
    });

    res.json(reviews);
  } catch (error) {
    console.error('Review history error:', error);
    res.status(500).json({ error: 'Failed to fetch review history' });
  }
});

// 取得用戶複習統計
router.get('/stats', authMiddleware, async (req: AuthRequest, res) => {
  try {
    const today = new Date();
    today.setHours(0, 0, 0, 0);

    const tomorrow = new Date(today);
    tomorrow.setDate(tomorrow.getDate() + 1);

    // 今日複習數
    const todayReviews = await prisma.reviewRecord.count({
      where: {
        userId: req.userId,
        createdAt: {
          gte: today,
          lt: tomorrow
        }
      }
    });

    // 總複習數
    const totalReviews = await prisma.reviewRecord.count({
      where: { userId: req.userId }
    });

    // 正確複習數
    const correctReviews = await prisma.reviewRecord.count({
      where: {
        userId: req.userId,
        quality: { gt: 0 }
      }
    });

    res.json({
      todayReviews,
      totalReviews,
      correctReviews,
      accuracy: totalReviews > 0 ? (correctReviews / totalReviews) * 100 : 0
    });
  } catch (error) {
    console.error('Review stats error:', error);
    res.status(500).json({ error: 'Failed to fetch review stats' });
  }
});

export default router;

