import axios from 'axios';
import { prisma } from '../config/database';
import { generateCardsFromMarkdown } from './cardGenerator';

const GITHUB_API_BASE = 'https://api.github.com';

/**
 * Sync cards from GitHub repository
 */
export async function syncCardsFromGitHub(fileName: string, userId: string) {
  try {
    const repo = process.env.GITHUB_REPO;
    const token = process.env.GITHUB_TOKEN;

    if (!repo || !token) {
      throw new Error('GitHub credentials not configured');
    }

    // 從 GitHub 取得文件內容
    const response = await axios.get(
      `${GITHUB_API_BASE}/repos/${repo}/contents/${fileName}`,
      {
        headers: {
          Authorization: `token ${token}`,
          Accept: 'application/vnd.github.v3.raw'
        }
      }
    );

    const content = response.data;

    // 提取章節和 domain（從檔案路徑）
    // 例如：PMP備考/UDEMY CH.1 PMP TERMS/何謂專案.md
    const chapterMatch = fileName.match(/UDEMY\s+CH\.(\d+)/i);
    const chapter = chapterMatch ? `CH.${chapterMatch[1]}` : 'Unknown';

    // 嘗試從文件內容提取 domain
    const domainMatch = content.match(/domain:\s*"([^"]+)"/i);
    const domain = domainMatch ? domainMatch[1] : 'Unknown';

    // 生成卡片
    const result = await generateCardsFromMarkdown(
      userId,
      fileName,
      content,
      chapter,
      domain
    );

    // 記錄同步
    await prisma.syncLog.create({
      data: {
        fileName,
        status: 'success',
        cardsGenerated: result.created
      }
    });

    return result;
  } catch (error: any) {
    console.error(`Failed to sync ${fileName}:`, error.message);

    // 記錄失敗
    await prisma.syncLog.create({
      data: {
        fileName,
        status: 'failed',
        error: error.message || 'Unknown error'
      }
    });

    throw error;
  }
}

/**
 * Extract GitHub user from repository owner
 */
export function extractGitHubUser(repoOwner: string): { email: string; username: string } {
  return {
    email: `${repoOwner}@github.com`,
    username: repoOwner
  };
}

/**
 * Filter Markdown files from commit
 */
export function filterMarkdownFiles(files: string[]): string[] {
  return files.filter((f) => {
    // 只包含 UDEMY 資料夾中的 Markdown 檔案
    return /UDEMY.*\.md$/i.test(f);
  });
}

import { Router, Request, Response } from 'express';
import crypto from 'crypto';
import { syncCardsFromGitHub, filterMarkdownFiles, extractGitHubUser } from '../services/githubSync';
import { prisma } from '../config/database';

const router = Router();

/**
 * Verify GitHub webhook signature
 */
function verifyGitHubSignature(req: Request): boolean {
  const signature = req.headers['x-hub-signature-256'] as string;
  const secret = process.env.GITHUB_WEBHOOK_SECRET;

  if (!signature || !secret) {
    return false;
  }

  const hash = crypto
    .createHmac('sha256', secret)
    .update(JSON.stringify(req.body))
    .digest('hex');

  return signature === `sha256=${hash}`;
}

/**
 * GitHub push event webhook
 * Triggered when files are pushed to GitHub
 */
router.post('/github', async (req: Request, res: Response) => {
  try {
    // 驗證簽名
    if (!verifyGitHubSignature(req)) {
      return res.status(401).json({ error: 'Invalid signature' });
    }

    const { ref, repository, commits } = req.body;

    // 只處理 main 分支
    if (ref !== 'refs/heads/main') {
      return res.json({ skipped: 'not main branch' });
    }

    // 查找被修改的筆記文件
    const allFiles = commits
      .flatMap((c: any) => [...(c.added || []), ...(c.modified || [])])
      .filter((f: string) => typeof f === 'string');

    const modifiedFiles = filterMarkdownFiles(allFiles);

    if (modifiedFiles.length === 0) {
      return res.json({ processed: 0 });
    }

    // 查找或創建用戶（使用倉庫擁有者作為用戶）
    const { email: ownerEmail, username: ownerUsername } = extractGitHubUser(
      repository.owner.login
    );

    let user = await prisma.user.findUnique({
      where: { email: ownerEmail }
    });

    if (!user) {
      user = await prisma.user.create({
        data: {
          email: ownerEmail,
          username: ownerUsername
        }
      });
    }

    // 同步每個文件
    let totalGenerated = 0;
    let totalUpdated = 0;
    const errors: Array<{ file: string; error: string }> = [];

    for (const file of modifiedFiles) {
      try {
        const result = await syncCardsFromGitHub(file, user.id);
        totalGenerated += result.created;
        totalUpdated += result.updated;
      } catch (error: any) {
        console.error(`Failed to sync ${file}:`, error);
        errors.push({
          file,
          error: error.message || 'Unknown error'
        });
      }
    }

    res.json({
      processed: modifiedFiles.length,
      cardsGenerated: totalGenerated,
      cardsUpdated: totalUpdated,
      errors: errors.length > 0 ? errors : undefined
    });
  } catch (error) {
    console.error('Webhook error:', error);
    res.status(500).json({ error: 'Webhook processing failed' });
  }
});

/**
 * Manual sync endpoint (for testing)
 */
router.post('/manual', async (req: Request, res: Response) => {
  try {
    const { fileName, userId } = req.body;

    if (!fileName || !userId) {
      return res.status(400).json({ error: 'Missing fileName or userId' });
    }

    const result = await syncCardsFromGitHub(fileName, userId);
    res.json(result);
  } catch (error: any) {
    res.status(500).json({ error: error.message || 'Sync failed' });
  }
});

/**
 * Get sync logs
 */
router.get('/logs', async (req: Request, res: Response) => {
  try {
    const limit = parseInt(req.query.limit as string) || 20;

    const logs = await prisma.syncLog.findMany({
      orderBy: { createdAt: 'desc' },
      take: limit
    });

    res.json(logs);
  } catch (error) {
    res.status(500).json({ error: 'Failed to fetch sync logs' });
  }
});

export default router;

