import axios, { AxiosInstance } from 'axios';
import { Card, ReviewInput } from '../types';

const API_URL = process.env.REACT_APP_API_URL || 'http://localhost:3000';

const client: AxiosInstance = axios.create({
  baseURL: `${API_URL}/api`,
  headers: {
    'Content-Type': 'application/json'
  }
});

// 添加認證 token 到請求頭
client.interceptors.request.use((config) => {
  const token = localStorage.getItem('auth_token');
  if (token) {
    config.headers.Authorization = `Bearer ${token}`;
  }
  return config;
});

// 處理響應錯誤
client.interceptors.response.use(
  (response) => response,
  (error) => {
    if (error.response?.status === 401) {
      // 清除 token，重定向到登錄
      localStorage.removeItem('auth_token');
      window.location.href = '/login';
    }
    return Promise.reject(error);
  }
);

export const cardAPI = {
  /**
   * 取得所有卡片
   */
  getAll: async () => {
    const response = await client.get<Card[]>('/cards');
    return response.data;
  },

  /**
   * 取得今日待複習卡片
   */
  getToday: async () => {
    const response = await client.get<Card[]>('/cards/today');
    return response.data;
  },

  /**
   * 創建新卡片
   */
  create: async (data: Partial<Card>) => {
    const response = await client.post<Card>('/cards', data);
    return response.data;
  },

  /**
   * 更新卡片
   */
  update: async (id: string, data: Partial<Card>) => {
    const response = await client.put<Card>(`/cards/${id}`, data);
    return response.data;
  },

  /**
   * 刪除卡片
   */
  delete: async (id: string) => {
    await client.delete(`/cards/${id}`);
    return { success: true };
  }
};

export const reviewAPI = {
  /**
   * 提交複習結果
   */
  submit: async (data: ReviewInput) => {
    const response = await client.post<{
      review: any;
      card: Card;
    }>('/review/submit', data);
    return response.data;
  },

  /**
   * 取得卡片的複習歷史
   */
  getHistory: async (cardId: string) => {
    const response = await client.get(`/review/history/${cardId}`);
    return response.data;
  },

  /**
   * 取得複習統計
   */
  getStats: async () => {
    const response = await client.get<{
      todayReviews: number;
      totalReviews: number;
      correctReviews: number;
      accuracy: number;
    }>('/review/stats');
    return response.data;
  }
};

export default client;

import { create } from 'zustand';
import { Card } from '../types';

export interface CardStoreState {
  cards: Card[];
  todayCards: Card[];
  isLoading: boolean;
  error: string | null;

  setCards: (cards: Card[]) => void;
  setTodayCards: (cards: Card[]) => void;
  setLoading: (loading: boolean) => void;
  setError: (error: string | null) => void;

  addCard: (card: Card) => void;
  removeCard: (cardId: string) => void;
  updateCard: (cardId: string, updates: Partial<Card>) => void;

  clear: () => void;
}

export const useCardStore = create<CardStoreState>((set) => ({
  cards: [],
  todayCards: [],
  isLoading: false,
  error: null,

  setCards: (cards) =>
    set({
      cards,
      error: null
    }),

  setTodayCards: (cards) =>
    set({
      todayCards: cards,
      error: null
    }),

  setLoading: (loading) =>
    set({
      isLoading: loading
    }),

  setError: (error) =>
    set({
      error
    }),

  addCard: (card) =>
    set((state) => ({
      cards: [...state.cards, card],
      todayCards: [...state.todayCards, card]
    })),

  removeCard: (cardId) =>
    set((state) => ({
      cards: state.cards.filter((c) => c.id !== cardId),
      todayCards: state.todayCards.filter((c) => c.id !== cardId)
    })),

  updateCard: (cardId, updates) =>
    set((state) => ({
      cards: state.cards.map((c) =>
        c.id === cardId ? { ...c, ...updates } : c
      ),
      todayCards: state.todayCards.map((c) =>
        c.id === cardId ? { ...c, ...updates } : c
      )
    })),

  clear: () =>
    set({
      cards: [],
      todayCards: [],
      isLoading: false,
      error: null
    })
}));

import { useEffect } from 'react';
import { useQuery, useMutation, useQueryClient } from '@tanstack/react-query';
import { cardAPI, reviewAPI } from '../api/client';
import { useCardStore } from '../store/cardStore';
import { Card, ReviewInput } from '../types';

/**
 * Hook to fetch all cards
 */
export function useCards() {
  const { cards, setCards, isLoading, setLoading, setError } = useCardStore();
  const queryClient = useQueryClient();

  const query = useQuery({
    queryKey: ['cards'],
    queryFn: async () => {
      setLoading(true);
      try {
        const data = await cardAPI.getAll();
        setCards(data);
        return data;
      } catch (error: any) {
        setError(error.message || 'Failed to fetch cards');
        throw error;
      } finally {
        setLoading(false);
      }
    },
    staleTime: 1000 * 60 * 5, // 5 minutes
  });

  return {
    cards,
    isLoading: query.isLoading || isLoading,
    error: query.error as Error | null,
    refetch: query.refetch
  };
}

/**
 * Hook to fetch today's cards
 */
export function useTodayCards() {
  const { todayCards, setTodayCards, setError } = useCardStore();

  const query = useQuery({
    queryKey: ['todayCards'],
    queryFn: async () => {
      try {
        const data = await cardAPI.getToday();
        setTodayCards(data);
        return data;
      } catch (error: any) {
        setError(error.message || 'Failed to fetch today cards');
        throw error;
      }
    },
    staleTime: 1000 * 60 * 5, // 5 minutes
  });

  return {
    cards: todayCards,
    isLoading: query.isLoading,
    error: query.error as Error | null,
    refetch: query.refetch
  };
}

/**
 * Hook to submit review and update card
 */
export function useSubmitReview() {
  const { updateCard } = useCardStore();
  const queryClient = useQueryClient();

  const mutation = useMutation({
    mutationFn: async (data: ReviewInput) => {
      return reviewAPI.submit(data);
    },
    onSuccess: (data) => {
      // 更新本地卡片狀態
      updateCard(data.card.id, data.card);

      // 更新 React Query 緩存
      queryClient.setQueryData(['cards'], (oldData: Card[] | undefined) => {
        if (!oldData) return oldData;
        return oldData.map((c) =>
          c.id === data.card.id ? { ...c, ...data.card } : c
        );
      });

      queryClient.setQueryData(['todayCards'], (oldData: Card[] | undefined) => {
        if (!oldData) return oldData;
        return oldData.map((c) =>
          c.id === data.card.id ? { ...c, ...data.card } : c
        );
      });
    }
  });

  return mutation;
}

/**
 * Hook to create a new card
 */
export function useCreateCard() {
  const { addCard } = useCardStore();
  const queryClient = useQueryClient();

  const mutation = useMutation({
    mutationFn: async (data: Partial<Card>) => {
      return cardAPI.create(data);
    },
    onSuccess: (newCard) => {
      addCard(newCard);
      queryClient.invalidateQueries({ queryKey: ['cards'] });
      queryClient.invalidateQueries({ queryKey: ['todayCards'] });
    }
  });

  return mutation;
}

/**
 * Hook to update a card
 */
export function useUpdateCard() {
  const { updateCard } = useCardStore();
  const queryClient = useQueryClient();

  const mutation = useMutation({
    mutationFn: async ({ id, data }: { id: string; data: Partial<Card> }) => {
      return cardAPI.update(id, data);
    },
    onSuccess: (updated) => {
      updateCard(updated.id, updated);
      queryClient.invalidateQueries({ queryKey: ['cards'] });
      queryClient.invalidateQueries({ queryKey: ['todayCards'] });
    }
  });

  return mutation;
}

/**
 * Hook to delete a card
 */
export function useDeleteCard() {
  const { removeCard } = useCardStore();
  const queryClient = useQueryClient();

  const mutation = useMutation({
    mutationFn: async (id: string) => {
      return cardAPI.delete(id);
    },
    onSuccess: (_, cardId) => {
      removeCard(cardId);
      queryClient.invalidateQueries({ queryKey: ['cards'] });
      queryClient.invalidateQueries({ queryKey: ['todayCards'] });
    }
  });

  return mutation;
}

import { useQuery } from '@tanstack/react-query';
import { reviewAPI } from '../api/client';

export interface ReviewStats {
  todayReviews: number;
  totalReviews: number;
  correctReviews: number;
  accuracy: number;
}

/**
 * Hook to fetch review statistics
 */
export function useReviewStats() {
  const query = useQuery({
    queryKey: ['reviewStats'],
    queryFn: async () => {
      return reviewAPI.getStats();
    },
    staleTime: 1000 * 60 * 5, // 5 minutes
  });

  return {
    stats: query.data as ReviewStats | undefined,
    isLoading: query.isLoading,
    error: query.error as Error | null,
    refetch: query.refetch
  };
}

/**
 * Calculate card statistics from card list
 */
export function calculateCardStats(cards: any[]) {
  const total = cards.length;
  const mastered = cards.filter((c) => c.correctCount >= c.totalReviews * 0.8).length;
  const learning = cards.filter((c) => c.totalReviews > 0 && c.totalReviews <= 5).length;
  const newCards = cards.filter((c) => c.totalReviews === 0).length;

  const today = new Date();
  today.setHours(0, 0, 0, 0);
  const overdue = cards.filter((c) => new Date(c.nextReviewDate) <= today).length;

  return {
    totalCards: total,
    masteredCards: mastered,
    learningCards: learning,
    newCards,
    overdueCards: overdue,
    masteryPercentage: total > 0 ? Math.round((mastered / total) * 100) : 0
  };
}

