import React, { useState, useEffect } from 'react';
import { Card } from '../types';

interface CardEditorProps {
  card?: Card;
  onSave: (data: Partial<Card>) => void;
  onCancel: () => void;
  isLoading?: boolean;
}

export const CardEditor: React.FC<CardEditorProps> = ({
  card,
  onSave,
  onCancel,
  isLoading = false
}) => {
  const [formData, setFormData] = useState<Partial<Card>>(
    card || {
      question: '',
      answer: '',
      difficulty: 'medium',
      tags: []
    }
  );

  const [tagInput, setTagInput] = useState('');

  useEffect(() => {
    if (card) {
      setFormData(card);
    }
  }, [card]);

  const handleChange = (
    e: React.ChangeEvent<
      HTMLInputElement | HTMLTextAreaElement | HTMLSelectElement
    >
  ) => {
    const { name, value } = e.target;
    setFormData((prev) => ({
      ...prev,
      [name]: value
    }));
  };

  const handleAddTag = () => {
    if (tagInput.trim() && formData.tags) {
      if (!formData.tags.includes(tagInput.trim())) {
        setFormData((prev) => ({
          ...prev,
          tags: [...(prev.tags || []), tagInput.trim()]
        }));
      }
      setTagInput('');
    }
  };

  const handleRemoveTag = (tag: string) => {
    setFormData((prev) => ({
      ...prev,
      tags: (prev.tags || []).filter((t) => t !== tag)
    }));
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (formData.question && formData.answer) {
      onSave(formData);
    }
  };

  return (
    <div className="bg-white rounded-lg shadow-lg p-6">
      <h2 className="text-2xl font-bold mb-6">
        {card ? 'Edit Card' : 'Create New Card'}
      </h2>

      <form onSubmit={handleSubmit} className="space-y-6">
        {/* Question */}
        <div>
          <label className="block text-sm font-medium text-gray-700 mb-2">
            Question *
          </label>
          <input
            type="text"
            name="question"
            value={formData.question || ''}
            onChange={handleChange}
            placeholder="Enter the question"
            className="w-full px-4 py-2 border border-gray-300 rounded-lg focus:ring-2 focus:ring-blue-500 focus:border-transparent"
            required
          />
        </div>

        {/* Answer */}
        <div>
          <label className="block text-sm font-medium text-gray-700 mb-2">
            Answer *
          </label>
          <textarea
            name="answer"
            value={formData.answer || ''}
            onChange={handleChange}
            placeholder="Enter the answer"
            rows={6}
            className="w-full px-4 py-2 border border-gray-300 rounded-lg focus:ring-2 focus:ring-blue-500 focus:border-transparent resize-none"
            required
          />
        </div>

        {/* Difficulty */}
        <div>
          <label className="block text-sm font-medium text-gray-700 mb-2">
            Difficulty
          </label>
          <select
            name="difficulty"
            value={formData.difficulty || 'medium'}
            onChange={handleChange}
            className="w-full px-4 py-2 border border-gray-300 rounded-lg focus:ring-2 focus:ring-blue-500 focus:border-transparent"
          >
            <option value="easy">Easy</option>
            <option value="medium">Medium</option>
            <option value="hard">Hard</option>
          </select>
        </div>

        {/* Tags */}
        <div>
          <label className="block text-sm font-medium text-gray-700 mb-2">
            Tags
          </label>
          <div className="flex gap-2 mb-2">
            <input
              type="text"
              value={tagInput}
              onChange={(e) => setTagInput(e.target.value)}
              onKeyPress={(e) => {
                if (e.key === 'Enter') {
                  e.preventDefault();
                  handleAddTag();
                }
              }}
              placeholder="Add a tag and press Enter"
              className="flex-1 px-4 py-2 border border-gray-300 rounded-lg focus:ring-2 focus:ring-blue-500 focus:border-transparent"
            />
            <button
              type="button"
              onClick={handleAddTag}
              className="px-4 py-2 bg-blue-500 text-white rounded-lg hover:bg-blue-600"
            >
              Add
            </button>
          </div>

          {/* Tags Display */}
          {formData.tags && formData.tags.length > 0 && (
            <div className="flex flex-wrap gap-2">
              {formData.tags.map((tag) => (
                <span
                  key={tag}
                  className="inline-flex items-center gap-1 px-3 py-1 bg-blue-100 text-blue-700 rounded-full text-sm"
                >
                  {tag}
                  <button
                    type="button"
                    onClick={() => handleRemoveTag(tag)}
                    className="hover:text-blue-900"
                  >
                    ×
                  </button>
                </span>
              ))}
            </div>
          )}
        </div>

        {/* Info Display */}
        {card && (
          <div className="bg-gray-50 p-4 rounded-lg text-sm text-gray-600">
            <p>
              <strong>Total Reviews:</strong> {card.totalReviews}
            </p>
            <p>
              <strong>Correct Answers:</strong> {card.correctCount}
            </p>
            <p>
              <strong>Next Review:</strong>{' '}
              {new Date(card.nextReviewDate).toLocaleDateString()}
            </p>
          </div>
        )}

        {/* Buttons */}
        <div className="flex gap-3 justify-end">
          <button
            type="button"
            onClick={onCancel}
            disabled={isLoading}
            className="px-6 py-2 border border-gray-300 rounded-lg text-gray-700 hover:bg-gray-50 disabled:opacity-50"
          >
            Cancel
          </button>
          <button
            type="submit"
            disabled={isLoading || !formData.question || !formData.answer}
            className="px-6 py-2 bg-blue-600 text-white rounded-lg hover:bg-blue-700 disabled:opacity-50"
          >
            {isLoading ? 'Saving...' : card ? 'Update Card' : 'Create Card'}
          </button>
        </div>
      </form>
    </div>
  );
};

import React, { useState } from 'react';
import { useCards } from '../hooks/useCards';
import { CardEditor } from '../components/CardEditor';
import { Card } from '../types';
import client from '../api/client';

export const CardsPage: React.FC = () => {
  const { cards, isLoading: cardsLoading, refetch } = useCards();
  const [searchTerm, setSearchTerm] = useState('');
  const [filterDifficulty, setFilterDifficulty] = useState<string>('all');
  const [filterDomain, setFilterDomain] = useState<string>('all');
  const [editingCard, setEditingCard] = useState<Card | null>(null);
  const [isCreating, setIsCreating] = useState(false);
  const [isSaving, setIsSaving] = useState(false);
  const [selectedCards, setSelectedCards] = useState<Set<string>>(new Set());

  // Filter cards
  const filteredCards = cards.filter((card) => {
    const matchesSearch =
      card.question.toLowerCase().includes(searchTerm.toLowerCase()) ||
      card.answer.toLowerCase().includes(searchTerm.toLowerCase());

    const matchesDifficulty =
      filterDifficulty === 'all' || card.difficulty === filterDifficulty;

    const matchesDomain =
      filterDomain === 'all' || card.domain === filterDomain;

    return matchesSearch && matchesDifficulty && matchesDomain;
  });

  // Get unique domains
  const domains = Array.from(new Set(cards.map((c) => c.domain)));

  // Handle save card
  const handleSaveCard = async (data: Partial<Card>) => {
    try {
      setIsSaving(true);

      if (editingCard) {
        // Update existing card
        await client.patch(`/cards/${editingCard.id}`, data);
      } else {
        // Create new card
        await client.post('/cards', data);
      }

      setEditingCard(null);
      setIsCreating(false);
      await refetch();
    } catch (error) {
      console.error('Failed to save card:', error);
      alert('Failed to save card');
    } finally {
      setIsSaving(false);
    }
  };

  // Handle delete card
  const handleDeleteCard = async (cardId: string) => {
    if (window.confirm('Are you sure you want to delete this card?')) {
      try {
        await client.delete(`/cards/${cardId}`);
        await refetch();
      } catch (error) {
        console.error('Failed to delete card:', error);
        alert('Failed to delete card');
      }
    }
  };

  // Handle bulk delete
  const handleBulkDelete = async () => {
    if (selectedCards.size === 0) {
      alert('Please select cards to delete');
      return;
    }

    if (
      window.confirm(
        `Are you sure you want to delete ${selectedCards.size} card(s)?`
      )
    ) {
      try {
        for (const cardId of selectedCards) {
          await client.delete(`/cards/${cardId}`);
        }
        setSelectedCards(new Set());
        await refetch();
      } catch (error) {
        console.error('Failed to delete cards:', error);
        alert('Failed to delete cards');
      }
    }
  };

  // Toggle card selection
  const toggleCardSelection = (cardId: string) => {
    const newSelected = new Set(selectedCards);
    if (newSelected.has(cardId)) {
      newSelected.delete(cardId);
    } else {
      newSelected.add(cardId);
    }
    setSelectedCards(newSelected);
  };

  // Toggle all selection
  const toggleAllSelection = () => {
    if (selectedCards.size === filteredCards.length) {
      setSelectedCards(new Set());
    } else {
      setSelectedCards(new Set(filteredCards.map((c) => c.id)));
    }
  };

  if (isCreating || editingCard) {
    return (
      <div className="min-h-screen bg-gray-50 p-8">
        <div className="max-w-4xl mx-auto">
          <CardEditor
            card={editingCard || undefined}
            onSave={handleSaveCard}
            onCancel={() => {
              setEditingCard(null);
              setIsCreating(false);
            }}
            isLoading={isSaving}
          />
        </div>
      </div>
    );
  }

  return (
    <div className="min-h-screen bg-gray-50 p-8">
      <div className="max-w-7xl mx-auto">
        {/* Header */}
        <div className="mb-8 flex justify-between items-center">
          <div>
            <h1 className="text-4xl font-bold text-gray-900 mb-2">
              Manage Cards
            </h1>
            <p className="text-gray-600">
              Edit, delete, or create flashcards
            </p>
          </div>
          <button
            onClick={() => setIsCreating(true)}
            className="px-6 py-3 bg-blue-600 text-white rounded-lg hover:bg-blue-700 font-medium"
          >
            + New Card
          </button>
        </div>

        {/* Filters */}
        <div className="bg-white rounded-lg shadow p-6 mb-8">
          <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
            {/* Search */}
            <input
              type="text"
              placeholder="Search cards..."
              value={searchTerm}
              onChange={(e) => setSearchTerm(e.target.value)}
              className="px-4 py-2 border border-gray-300 rounded-lg focus:ring-2 focus:ring-blue-500 focus:border-transparent"
            />

            {/* Difficulty Filter */}
            <select
              value={filterDifficulty}
              onChange={(e) => setFilterDifficulty(e.target.value)}
              className="px-4 py-2 border border-gray-300 rounded-lg focus:ring-2 focus:ring-blue-500 focus:border-transparent"
            >
              <option value="all">All Difficulties</option>
              <option value="easy">Easy</option>
              <option value="medium">Medium</option>
              <option value="hard">Hard</option>
            </select>

            {/* Domain Filter */}
            <select
              value={filterDomain}
              onChange={(e) => setFilterDomain(e.target.value)}
              className="px-4 py-2 border border-gray-300 rounded-lg focus:ring-2 focus:ring-blue-500 focus:border-transparent"
            >
              <option value="all">All Domains</option>
              {domains.map((domain) => (
                <option key={domain} value={domain}>
                  {domain}
                </option>
              ))}
            </select>
          </div>
        </div>

        {/* Bulk Actions */}
        {selectedCards.size > 0 && (
          <div className="bg-blue-50 border border-blue-200 rounded-lg p-4 mb-8 flex justify-between items-center">
            <span className="text-blue-900 font-medium">
              {selectedCards.size} card(s) selected
            </span>
            <button
              onClick={handleBulkDelete}
              className="px-4 py-2 bg-red-600 text-white rounded-lg hover:bg-red-700"
            >
              Delete Selected
            </button>
          </div>
        )}

        {/* Cards Table */}
        <div className="bg-white rounded-lg shadow overflow-hidden">
          {cardsLoading ? (
            <div className="p-8 text-center text-gray-500">
              Loading cards...
            </div>
          ) : filteredCards.length === 0 ? (
            <div className="p-8 text-center text-gray-500">
              No cards found
            </div>
          ) : (
            <table className="w-full">
              <thead className="bg-gray-50 border-b border-gray-200">
                <tr>
                  <th className="px-6 py-3 text-left">
                    <input
                      type="checkbox"
                      checked={
                        selectedCards.size === filteredCards.length &&
                        filteredCards.length > 0
                      }
                      onChange={toggleAllSelection}
                      className="rounded"
                    />
                  </th>
                  <th className="px-6 py-3 text-left text-sm font-semibold text-gray-900">
                    Question
                  </th>
                  <th className="px-6 py-3 text-left text-sm font-semibold text-gray-900">
                    Domain
                  </th>
                  <th className="px-6 py-3 text-left text-sm font-semibold text-gray-900">
                    Difficulty
                  </th>
                  <th className="px-6 py-3 text-left text-sm font-semibold text-gray-900">
                    Reviews
                  </th>
                  <th className="px-6 py-3 text-left text-sm font-semibold text-gray-900">
                    Accuracy
                  </th>
                  <th className="px-6 py-3 text-right text-sm font-semibold text-gray-900">
                    Actions
                  </th>
                </tr>
              </thead>
              <tbody className="divide-y divide-gray-200">
                {filteredCards.map((card) => (
                  <tr key={card.id} className="hover:bg-gray-50">
                    <td className="px-6 py-4">
                      <input
                        type="checkbox"
                        checked={selectedCards.has(card.id)}
                        onChange={() => toggleCardSelection(card.id)}
                        className="rounded"
                      />
                    </td>
                    <td className="px-6 py-4">
                      <div className="max-w-sm">
                        <p className="text-sm font-medium text-gray-900 truncate">
                          {card.question}
                        </p>
                      </div>
                    </td>
                    <td className="px-6 py-4 text-sm text-gray-600">
                      {card.domain}
                    </td>
                    <td className="px-6 py-4 text-sm">
                      <span
                        className={`px-3 py-1 rounded-full text-xs font-medium ${
                          card.difficulty === 'easy'
                            ? 'bg-green-100 text-green-800'
                            : card.difficulty === 'medium'
                            ? 'bg-yellow-100 text-yellow-800'
                            : 'bg-red-100 text-red-800'
                        }`}
                      >
                        {card.difficulty}
                      </span>
                    </td>
                    <td className="px-6 py-4 text-sm text-gray-600">
                      {card.totalReviews}
                    </td>
                    <td className="px-6 py-4 text-sm text-gray-600">
                      {card.totalReviews > 0
                        ? Math.round(
                            (card.correctCount / card.totalReviews) * 100
                          )
                        : 0}
                      %
                    </td>
                    <td className="px-6 py-4 text-right">
                      <button
                        onClick={() => setEditingCard(card)}
                        className="text-blue-600 hover:text-blue-900 font-medium mr-4"
                      >
                        Edit
                      </button>
                      <button
                        onClick={() => handleDeleteCard(card.id)}
                        className="text-red-600 hover:text-red-900 font-medium"
                      >
                        Delete
                      </button>
                    </td>
                  </tr>
                ))}
              </tbody>
            </table>
          )}
        </div>

        {/* Summary */}
        <div className="mt-8 grid grid-cols-1 md:grid-cols-4 gap-4">
          <div className="bg-white rounded-lg shadow p-4">
            <p className="text-gray-600 text-sm">Total Cards</p>
            <p className="text-3xl font-bold text-gray-900">{cards.length}</p>
          </div>
          <div className="bg-white rounded-lg shadow p-4">
            <p className="text-gray-600 text-sm">Filtered Results</p>
            <p className="text-3xl font-bold text-blue-600">
              {filteredCards.length}
            </p>
          </div>
          <div className="bg-white rounded-lg shadow p-4">
            <p className="text-gray-600 text-sm">Selected</p>
            <p className="text-3xl font-bold text-green-600">
              {selectedCards.size}
            </p>
          </div>
          <div className="bg-white rounded-lg shadow p-4">
            <p className="text-gray-600 text-sm">Avg Accuracy</p>
            <p className="text-3xl font-bold text-purple-600">
              {cards.length > 0
                ? Math.round(
                    (cards.reduce((sum, c) => sum + c.correctCount, 0) /
                      cards.reduce((sum, c) => sum + c.totalReviews, 0)) *
                      100
                  )
                : 0}
              %
            </p>
          </div>
        </div>
      </div>
    </div>
  );
};

import React, { useState, useEffect } from 'react';
import {
  clearOfflineData,
  isOnline,
  onlineOfflineListener
} from '../utils/offlineStorage';
import client from '../api/client';

interface Settings {
  dailyGoal: number;
  reviewMode: 'all' | 'new-first' | 'overdue-first';
  newCardsPerDay: number;
  enableNotifications: boolean;
  enableOfflineMode: boolean;
  enableAnalytics: boolean;
  theme: 'light' | 'dark' | 'auto';
}

const DEFAULT_SETTINGS: Settings = {
  dailyGoal: 20,
  reviewMode: 'overdue-first',
  newCardsPerDay: 5,
  enableNotifications: true,
  enableOfflineMode: true,
  enableAnalytics: true,
  theme: 'light'
};

export const SettingsPage: React.FC = () => {
  const [settings, setSettings] = useState<Settings>(DEFAULT_SETTINGS);
  const [isSaving, setIsSaving] = useState(false);
  const [saveSuccess, setSaveSuccess] = useState(false);
  const [isOnlineStatus, setIsOnlineStatus] = useState(isOnline());
  const [swRegistered, setSwRegistered] = useState(false);
  const [cacheSize, setCacheSize] = useState(0);

  useEffect(() => {
    // Load settings from localStorage
    const saved = localStorage.getItem('app_settings');
    if (saved) {
      setSettings(JSON.parse(saved));
    }

    // Check service worker
    if ('serviceWorker' in navigator) {
      navigator.serviceWorker
        .getRegistrations()
        .then((registrations) => {
          setSwRegistered(registrations.length > 0);
        });
    }

    // Check offline cache size
    if ('caches' in window) {
      caches.keys().then((names) => {
        let total = 0;
        Promise.all(
          names.map((name) =>
            caches.open(name).then((cache) =>
              cache.keys().then((requests) => {
                total += requests.length;
                setCacheSize(total);
              })
            )
          )
        );
      });
    }

    // Listen to online/offline changes
    const unsubscribe = onlineOfflineListener((online) => {
      setIsOnlineStatus(online);
    });

    return unsubscribe;
  }, []);

  const handleChange = (
    field: keyof Settings,
    value: string | number | boolean
  ) => {
    setSettings((prev) => ({
      ...prev,
      [field]: value
    }));
  };

  const handleSaveSettings = async () => {
    try {
      setIsSaving(true);

      // Save to localStorage
      localStorage.setItem('app_settings', JSON.stringify(settings));

      // Try to sync with backend
      try {
        await client.post('/user/settings', settings);
      } catch (error) {
        console.log('Settings saved locally (offline mode)');
      }

      setSaveSuccess(true);
      setTimeout(() => setSaveSuccess(false), 3000);
    } finally {
      setIsSaving(false);
    }
  };

  const handleClearCache = async () => {
    if (
      window.confirm(
        'This will clear all cached data. Your progress will still be synced when you go online.'
      )
    ) {
      try {
        await clearOfflineData();
        setCacheSize(0);
        alert('Cache cleared successfully');
      } catch (error) {
        alert('Failed to clear cache');
      }
    }
  };

  const handleRegisterServiceWorker = async () => {
    if ('serviceWorker' in navigator) {
      try {
        const registration = await navigator.serviceWorker.register(
          '/service-worker.js'
        );
        setSwRegistered(true);
        alert('Service Worker registered successfully');
        console.log('Service Worker registered:', registration);
      } catch (error) {
        alert('Failed to register Service Worker');
        console.error('Service Worker registration failed:', error);
      }
    }
  };

  const handleExportData = async () => {
    try {
      // Fetch user data
      const response = await client.get('/export');
      const data = response.data;

      // Create JSON file
      const jsonStr = JSON.stringify(data, null, 2);
      const blob = new Blob([jsonStr], { type: 'application/json' });
      const url = window.URL.createObjectURL(blob);
      const a = document.createElement('a');
      a.href = url;
      a.download = `pmp-flashcard-backup-${Date.now()}.json`;
      document.body.appendChild(a);
      a.click();
      document.body.removeChild(a);
      window.URL.revokeObjectURL(url);
    } catch (error) {
      alert('Failed to export data');
      console.error('Export failed:', error);
    }
  };

  return (
    <div className="min-h-screen bg-gray-50 p-8">
      <div className="max-w-4xl mx-auto">
        {/* Header */}
        <div className="mb-8">
          <h1 className="text-4xl font-bold text-gray-900 mb-2">Settings</h1>
          <p className="text-gray-600">Customize your learning experience</p>
        </div>

        {/* Success Message */}
        {saveSuccess && (
          <div className="mb-6 bg-green-50 border border-green-200 text-green-800 px-4 py-3 rounded-lg">
            Settings saved successfully!
          </div>
        )}

        {/* Connection Status */}
        <div className="mb-8 bg-white rounded-lg shadow p-6">
          <div className="flex items-center justify-between">
            <div>
              <h2 className="text-lg font-semibold text-gray-900">
                Connection Status
              </h2>
              <p className="text-gray-600 mt-1">
                {isOnlineStatus ? '🟢 Online' : '🔴 Offline'}
              </p>
            </div>
            <div className="text-right">
              <p className="text-sm text-gray-600">Service Worker</p>
              <p className="text-lg font-semibold">
                {swRegistered ? '✓ Active' : '✗ Inactive'}
              </p>
            </div>
          </div>
        </div>

        {/* Learning Preferences */}
        <div className="bg-white rounded-lg shadow p-6 mb-6">
          <h2 className="text-xl font-bold text-gray-900 mb-6">
            Learning Preferences
          </h2>

          <div className="space-y-6">
            {/* Daily Goal */}
            <div>
              <label className="block text-sm font-medium text-gray-700 mb-2">
                Daily Review Goal
              </label>
              <div className="flex items-center gap-4">
                <input
                  type="range"
                  min="5"
                  max="100"
                  step="5"
                  value={settings.dailyGoal}
                  onChange={(e) =>
                    handleChange('dailyGoal', parseInt(e.target.value))
                  }
                  className="flex-1"
                />
                <span className="text-2xl font-bold text-blue-600 w-12">
                  {settings.dailyGoal}
                </span>
              </div>
              <p className="text-sm text-gray-500 mt-2">
                Cards per day to review
              </p>
            </div>

            {/* Review Mode */}
            <div>
              <label className="block text-sm font-medium text-gray-700 mb-3">
                Review Mode
              </label>
              <div className="space-y-2">
                {[
                  { value: 'overdue-first', label: 'Overdue First' },
                  { value: 'new-first', label: 'New Cards First' },
                  { value: 'all', label: 'All Mixed' }
                ].map((option) => (
                  <label key={option.value} className="flex items-center">
                    <input
