              </div>
              <button
                onClick={handleClearCache}
                className="px-4 py-2 bg-red-100 text-red-700 rounded-lg hover:bg-red-200"
              >
                Clear Cache
              </button>
            </div>

            {!swRegistered && (
              <div className="border-t pt-4">
                <button
                  onClick={handleRegisterServiceWorker}
                  className="px-4 py-2 bg-blue-600 text-white rounded-lg hover:bg-blue-700"
                >
                  Enable Offline Mode
                </button>
              </div>
            )}
          </div>
        </div>

        {/* Data Management */}
        <div className="bg-white rounded-lg shadow p-6 mb-6">
          <h2 className="text-xl font-bold text-gray-900 mb-6">
            Data Management
          </h2>

          <div className="space-y-3">
            <button
              onClick={handleExportData}
              className="w-full px-4 py-2 border border-gray-300 text-gray-700 rounded-lg hover:bg-gray-50"
            >
              📥 Export Data
            </button>
            <button
              className="w-full px-4 py-2 border border-gray-300 text-gray-700 rounded-lg hover:bg-gray-50"
            >
              📤 Import Data
            </button>
          </div>
        </div>

        {/* Save Button */}
        <div className="flex gap-3">
          <button
            onClick={handleSaveSettings}
            disabled={isSaving}
            className="flex-1 px-6 py-3 bg-blue-600 text-white rounded-lg hover:bg-blue-700 disabled:opacity-50 font-medium"
          >
            {isSaving ? 'Saving...' : 'Save Settings'}
          </button>
          <button
            onClick={() => setSettings(DEFAULT_SETTINGS)}
            className="px-6 py-3 border border-gray-300 text-gray-700 rounded-lg hover:bg-gray-50 font-medium"
          >
            Reset to Default
          </button>
        </div>
      </div>
    </div>
  );
};

/**
 * Performance optimization utilities
 */

/**
 * Debounce function for expensive operations
 */
export function debounce<T extends (...args: any[]) => any>(
  func: T,
  wait: number
): (...args: Parameters<T>) => void {
  let timeout: NodeJS.Timeout;

  return function executedFunction(...args: Parameters<T>) {
    const later = () => {
      clearTimeout(timeout);
      func(...args);
    };

    clearTimeout(timeout);
    timeout = setTimeout(later, wait);
  };
}

/**
 * Throttle function for frequent events
 */
export function throttle<T extends (...args: any[]) => any>(
  func: T,
  limit: number
): (...args: Parameters<T>) => void {
  let inThrottle: boolean;

  return function (...args: Parameters<T>) {
    if (!inThrottle) {
      func(...args);
      inThrottle = true;
      setTimeout(() => (inThrottle = false), limit);
    }
  };
}

/**
 * Memoization for expensive computations
 */
export function memoize<T extends (...args: any[]) => any>(func: T): T {
  const cache = new Map();

  return ((...args: any[]) => {
    const key = JSON.stringify(args);

    if (cache.has(key)) {
      return cache.get(key);
    }

    const result = func(...args);
    cache.set(key, result);
    return result;
  }) as T;
}

/**
 * Lazy load images
 */
export function setupImageLazyLoading(): void {
  if ('IntersectionObserver' in window) {
    const images = document.querySelectorAll('img[data-src]');

    const imageObserver = new IntersectionObserver((entries, observer) => {
      entries.forEach((entry) => {
        if (entry.isIntersecting) {
          const img = entry.target as HTMLImageElement;
          img.src = img.dataset.src || '';
          img.removeAttribute('data-src');
          observer.unobserve(img);
        }
      });
    });

    images.forEach((img) => imageObserver.observe(img));
  } else {
    // Fallback for browsers that don't support IntersectionObserver
    const images = document.querySelectorAll('img[data-src]');
    images.forEach((img: any) => {
      img.src = img.dataset.src;
      img.removeAttribute('data-src');
    });
  }
}

/**
 * Measure performance
 */
export function measurePerformance(label: string): () => void {
  const startTime = performance.now();

  return () => {
    const endTime = performance.now();
    const duration = endTime - startTime;
    console.log(`[Performance] ${label}: ${duration.toFixed(2)}ms`);

    // Send to analytics if available
    if (window.gtag) {
      window.gtag('event', 'timing_complete', {
        name: label,
        value: Math.round(duration),
        event_category: 'performance'
      });
    }
  };
}

/**
 * Request animation frame wrapper
 */
export function rafThrottle<T extends (...args: any[]) => any>(
  func: T
): (...args: Parameters<T>) => void {
  let ticking = false;

  return function (...args: Parameters<T>) {
    if (!ticking) {
      requestAnimationFrame(() => {
        func(...args);
        ticking = false;
      });
      ticking = true;
    }
  };
}

/**
 * Batch DOM updates
 */
export function batchDOMUpdates(
  updates: (() => void)[]
): void {
  requestAnimationFrame(() => {
    updates.forEach((update) => update());
  });
}

/**
 * Report Web Vitals
 */
export function reportWebVitals(callback: (metric: any) => void): void {
  // LCP (Largest Contentful Paint)
  if ('PerformanceObserver' in window) {
    try {
      const lcpObserver = new PerformanceObserver((list) => {
        const entries = list.getEntries();
        const lastEntry = entries[entries.length - 1] as any;
        callback({
          name: 'LCP',
          value: lastEntry.renderTime || lastEntry.loadTime,
          rating: lastEntry.renderTime || lastEntry.loadTime > 2500 ? 'poor' : 'good'
        });
      });
      lcpObserver.observe({ entryTypes: ['largest-contentful-paint'] });
    } catch (e) {
      console.log('LCP observer not supported');
    }

    // FID (First Input Delay)
    try {
      const fidObserver = new PerformanceObserver((list) => {
        list.getEntries().forEach((entry: any) => {
          callback({
            name: 'FID',
            value: entry.processingDuration,
            rating: entry.processingDuration > 100 ? 'poor' : 'good'
          });
        });
      });
      fidObserver.observe({ entryTypes: ['first-input'] });
    } catch (e) {
      console.log('FID observer not supported');
    }

    // CLS (Cumulative Layout Shift)
    try {
      let clsValue = 0;
      const clsObserver = new PerformanceObserver((list) => {
        list.getEntries().forEach((entry: any) => {
          if (!entry.hadRecentInput) {
            clsValue += entry.value;
            callback({
              name: 'CLS',
              value: clsValue,
              rating: clsValue > 0.1 ? 'poor' : 'good'
            });
          }
        });
      });
      clsObserver.observe({ entryTypes: ['layout-shift'] });
    } catch (e) {
      console.log('CLS observer not supported');
    }
  }
}

/**
 * Preload resources
 */
export function preloadResource(
  url: string,
  type: 'script' | 'style' | 'image'
): void {
  const link = document.createElement('link');
  link.rel = 'preload';
  link.as = type;
  link.href = url;
  document.head.appendChild(link);
}

/**
 * Cleanup performance monitoring
 */
export function cleanupPerformanceMonitoring(): void {
  // Remove performance entries older than 1 hour
  if ('clearResourceTimings' in performance) {
    performance.clearResourceTimings();
  }
}

/**
 * Global error handling and reporting
 */
export function setupErrorReporting(): void {
  window.addEventListener('error', (event) => {
    console.error('Global error:', event.error);

    // Send to error tracking service
    if (window.gtag) {
      window.gtag('event', 'exception', {
        description: event.error?.message || 'Unknown error',
        fatal: false
      });
    }
  });

  window.addEventListener('unhandledrejection', (event) => {
    console.error('Unhandled promise rejection:', event.reason);

    // Send to error tracking service
    if (window.gtag) {
      window.gtag('event', 'exception', {
        description: event.reason?.message || 'Unhandled promise rejection',
        fatal: false
      });
    }
  });
}

// Type augmentation for gtag
declare global {
  interface Window {
    gtag?: (command: string, action: string, params?: any) => void;
  }
}

export default {
  debounce,
  throttle,
  memoize,
  setupImageLazyLoading,
  measurePerformance,
  rafThrottle,
  batchDOMUpdates,
  reportWebVitals,
  preloadResource,
  cleanupPerformanceMonitoring,
  setupErrorReporting
};

import React, { useState, useCallback, useMemo } from 'react';
import { Card as CardType } from '../types';

interface OptimizedCardProps {
  card: CardType;
  onRate: (quality: number) => void | Promise<void>;
  isLoading?: boolean;
}

/**
 * Optimized card component with memoization and callback optimization
 */
export const OptimizedCard = React.memo<OptimizedCardProps>(
  ({ card, onRate, isLoading = false }) => {
    const [isFlipped, setIsFlipped] = useState(false);

    // Memoize flip handler
    const handleFlip = useCallback(() => {
      setIsFlipped((prev) => !prev);
    }, []);

    // Memoize rating handlers
    const handleRate0 = useCallback(() => onRate(0), [onRate]);
    const handleRate1 = useCallback(() => onRate(1), [onRate]);
    const handleRate2 = useCallback(() => onRate(2), [onRate]);
    const handleRate3 = useCallback(() => onRate(3), [onRate]);

    // Memoize metadata calculation
    const metadata = useMemo(
      () => ({
        accuracy:
          card.totalReviews > 0
            ? Math.round((card.correctCount / card.totalReviews) * 100)
            : 0,
        daysUntilReview: Math.ceil(
          (new Date(card.nextReviewDate).getTime() - Date.now()) /
            (1000 * 60 * 60 * 24)
        )
      }),
      [card]
    );

    return (
      <div className="w-full max-w-2xl mx-auto p-6">
        {/* Card */}
        <div
          className="bg-white rounded-lg shadow-lg p-8 min-h-64 cursor-pointer transition-all duration-300"
          onClick={handleFlip}
          role="button"
          tabIndex={0}
          onKeyPress={(e) => {
            if (e.key === 'Enter' || e.key === ' ') {
              e.preventDefault();
              handleFlip();
            }
          }}
          aria-pressed={isFlipped}
        >
          <div className="text-center">
            {!isFlipped ? (
              <>
                <p className="text-sm text-gray-500 mb-4 font-medium">
                  Question
                </p>
                <p className="text-xl font-semibold text-gray-900">
                  {card.question}
                </p>
              </>
            ) : (
              <>
                <p className="text-sm text-gray-500 mb-4 font-medium">
                  Answer
                </p>
                <p className="text-lg text-gray-900 whitespace-pre-wrap">
                  {card.answer}
                </p>
              </>
            )}
          </div>
        </div>

        {/* Rating Buttons */}
        <div className="mt-8 grid grid-cols-2 md:grid-cols-4 gap-3">
          <RatingButton
            label="Again"
            sublabel="(0)"
            onClick={handleRate0}
            disabled={isLoading}
            color="red"
          />
          <RatingButton
            label="Hard"
            sublabel="(1)"
            onClick={handleRate1}
            disabled={isLoading}
            color="yellow"
          />
          <RatingButton
            label="Good"
            sublabel="(2)"
            onClick={handleRate2}
            disabled={isLoading}
            color="green"
          />
          <RatingButton
            label="Easy"
            sublabel="(3)"
            onClick={handleRate3}
            disabled={isLoading}
            color="blue"
          />
        </div>

        {/* Metadata */}
        <div className="mt-6 p-4 bg-gray-50 rounded-lg">
          <div className="grid grid-cols-2 md:grid-cols-4 gap-4 text-xs">
            <div>
              <p className="text-gray-600">Chapter</p>
              <p className="font-semibold text-gray-900">{card.chapter}</p>
            </div>
            <div>
              <p className="text-gray-600">Domain</p>
              <p className="font-semibold text-gray-900">{card.domain}</p>
            </div>
            <div>
              <p className="text-gray-600">Reviews</p>
              <p className="font-semibold text-gray-900">{card.totalReviews}</p>
            </div>
            <div>
              <p className="text-gray-600">Accuracy</p>
              <p className="font-semibold text-gray-900">
                {metadata.accuracy}%
              </p>
            </div>
          </div>
        </div>

        {/* Difficulty Badge */}
        <div className="mt-4">
          <span
            className={`inline-block px-3 py-1 rounded-full text-xs font-medium ${
              card.difficulty === 'easy'
                ? 'bg-green-100 text-green-800'
                : card.difficulty === 'medium'
                ? 'bg-yellow-100 text-yellow-800'
                : 'bg-red-100 text-red-800'
            }`}
          >
            {card.difficulty.charAt(0).toUpperCase() +
              card.difficulty.slice(1)}{' '}
            Difficulty
          </span>
        </div>
      </div>
    );
  },
  (prevProps, nextProps) => {
    // Custom comparison for deep equality
    return (
      prevProps.card.id === nextProps.card.id &&
      prevProps.isLoading === nextProps.isLoading
    );
  }
);

OptimizedCard.displayName = 'OptimizedCard';

/**
 * Memoized rating button component
 */
interface RatingButtonProps {
  label: string;
  sublabel: string;
  onClick: () => void;
  disabled: boolean;
  color: 'red' | 'yellow' | 'green' | 'blue';
}

const RatingButton = React.memo<RatingButtonProps>(
  ({ label, sublabel, onClick, disabled, color }) => {
    const colorClasses = {
      red: 'bg-red-500 hover:bg-red-600',
      yellow: 'bg-yellow-500 hover:bg-yellow-600',
      green: 'bg-green-500 hover:bg-green-600',
      blue: 'bg-blue-500 hover:bg-blue-600'
    };

    return (
      <button
        onClick={onClick}
        disabled={disabled}
        className={`px-4 py-3 ${colorClasses[color]} text-white rounded-lg disabled:opacity-50 transition-colors font-medium text-sm`}
        aria-label={`${label} ${sublabel}`}
      >
        <div>{label}</div>
        <div className="text-xs opacity-75">{sublabel}</div>
      </button>
    );
  }
);

RatingButton.displayName = 'RatingButton';
